  padding: 4px 10px;
  border-radius: 12px;
  min-width: 35px;
  text-align: center;
}

widgets.scripts:
document.addEventListener('DOMContentLoaded', function() {
  const items = document.querySelectorAll('.dwm-category-item');
  const maxCount = Math.max(...Array.from(items).map(item => parseInt(item.querySelector('.dwm-category-count').dataset.count)));

  items.forEach((item, index) => {
    const count = parseInt(item.querySelector('.dwm-category-count').dataset.count);
    const percentage = (count / maxCount) * 100;
    item.style.setProperty('--percentage', percentage + '%');
    item.style.animation = `slideInCategory 0.5s ease ${index * 0.05}s both`;
  });
});

const style = document.createElement('style');
style.textContent = `
  @keyframes slideInCategory {
    from {
      opacity: 0;
      transform: translateX(-20px);
    }
    to {
      opacity: 1;
      transform: translateX(0);
    }
  }
`;
document.head.appendChild(style);

