widgets.scripts:
document.addEventListener('DOMContentLoaded', function() {
  const badges = document.querySelectorAll('.dwm-status-badge');
  const statusMap = {
    'publish': '✓',
    'draft': '✎',
    'pending': '⧖',
    'trash': '🗑',
    'private': '🔒'
  };

  badges.forEach((badge, index) => {
    const status = badge.dataset.status;
    const icon = statusMap[status] || '•';
    badge.insertAdjacentHTML('afterbegin', '<span class="dwm-status-icon">' + icon + '</span>');
    badge.style.animation = `popIn 0.4s cubic-bezier(0.34, 1.56, 0.64, 1) ${index * 0.08}s both`;
  });
});

const style = document.createElement('style');
style.textContent = `
  .dwm-status-icon {
    margin-right: 4px;
  }

  @keyframes popIn {
    from {
      opacity: 0;
      transform: scale(0.8);
    }
    to {
      opacity: 1;
      transform: scale(1);
    }
  }
`;
document.head.appendChild(style);

